7	<style>
8	:root { --bg:#0f1115; --card:#171a21; --muted:#8a93a6; --fg:#e5e9f0; --accent:#5b9bff; --green:#4ade80; --red:#f87171; --yellow:#facc15; --border:#262b35; }
9	*{box-sizing:border-box} body{margin:0;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;background:var(--bg);color:var(--fg);line-height:1.5}
10	.container{max-width:1180px;margin:0 auto;padding:32px 24px}
11	h1{font-size:26px;margin:0 0 4px} h2{font-size:18px;margin:24px 0 10px;color:var(--accent);border-bottom:1px solid var(--border);padding-bottom:6px}
12	h3{font-size:15px;margin:16px 0 8px;color:#b5bccc}
13	.sub{color:var(--muted);font-size:13px;margin-bottom:18px}
14	.grid{display:grid;gap:12px}
15	.grid-2{grid-template-columns:1fr 1fr}
16	.grid-3{grid-template-columns:1fr 1fr 1fr}
17	.grid-4{grid-template-columns:repeat(4,1fr)}
18	.card{background:var(--card);border:1px solid var(--border);border-radius:10px;padding:14px 16px}
19	.card .label{color:var(--muted);font-size:12px;letter-spacing:.04em;text-transform:uppercase}
20	.card .val{font-size:20px;margin-top:4px}
21	table{width:100%;border-collapse:collapse;font-size:13px;margin-top:6px}
22	th,td{padding:8px 10px;text-align:left;border-bottom:1px solid var(--border);vertical-align:top}
23	th{color:var(--muted);font-weight:500;background:#12151c}
24	tr:hover td{background:#1a1e27}
25	.pill{display:inline-block;padding:2px 8px;border-radius:10px;font-size:11px;font-weight:500}
26	.pill.green{background:rgba(74,222,128,.15);color:var(--green)} .pill.red{background:rgba(248,113,113,.15);color:var(--red)} .pill.yellow{background:rgba(250,204,21,.15);color:var(--yellow)} .pill.blue{background:rgba(91,155,255,.15);color:var(--accent)} .pill.gray{background:#262b35;color:var(--muted)} .pill.purple{background:rgba(167,139,250,.15);color:#a78bfa}
27	.chart-wrap{position:relative;height:260px}
28	.ok{color:var(--green)} .warn{color:var(--yellow)} .bad{color:var(--red)} .mute{color:var(--muted)}
29	.kv{display:grid;grid-template-columns:130px 1fr;gap:6px 12px;font-size:13px}
30	.kv .k{color:var(--muted)}
31	.footer{color:var(--muted);font-size:12px;margin-top:24px;border-top:1px solid var(--border);padding-top:12px}
32	ul{margin:6px 0;padding-left:20px} li{margin:3px 0}
33	.delta-box{background:#0d1a2e;border:1px solid #1f6feb;border-radius:8px;padding:14px 18px;margin-bottom:18px}
34	.delta-box h3{color:#79c0ff;margin-top:0}
35	</style>
36	</head>
